/**
 * Shared TypeScript types aligned with the Gateway OpenAPI specification.
 *
 * All API entity types are re-exported from `@/api/generated/gateway`
 * (the authoritative source generated by openapi-typescript).
 *
 * UI-only types (theme, navigation, etc.) and SSE payload data types
 * are defined here since they are not part of the gateway contract.
 */

import type { components } from '@/api/generated/gateway'

