// =============================================================================
// SSE data payload types (UI event shapes not part of the gateway contract)
// =============================================================================

export interface MessageCreatedData {
  messageId: string
  sessionId: string
  responseRunId: string
  sequenceNo: number
}

export interface AgentIterationStartedData {
  responseRunId: string
  iterationNo: number
}

export interface ReasoningStepData {
  responseRunId: string
  step: QAThinkingStep
}

export interface ToolStartedData {
  responseRunId: string
  toolCallId: string
  toolName: string
}

export interface ToolCompletedData {
  responseRunId: string
  toolCallId: string
  toolName: string
  latencyMs: number
}

export interface ToolFailedData {
  responseRunId: string
  toolCallId: string
  toolName: string
  errorCode: string
  errorMessage: string
}

export interface AnswerDeltaData {
  responseRunId: string
  content: string
  sequenceNo: number
}

export interface CitationDeltaData {
  responseRunId: string
  citation: QACitation
}

export interface AnswerCompletedData {
  responseRunId: string
  assistantMessageId: string
  totalTokens: number
  latencyMs: number
}

export interface SSEErrorData {
  responseRunId?: string
  code: string
  message: string
  fatal: boolean
}

