/** @deprecated Use PageInfo from generated instead. */
export type ListResult<T> = {
  items: T[]
  total: number
  page: number
  pageSize: number
}

/** @deprecated Use QARetrievalTestRunRequest instead. */
export type QAThinkingStepType =
  'agent_iteration' | 'tool_call' | 'tool_result' | 'generation' | 'citation' | 'verify'

/** @deprecated Use QAThinkingStep['status'] or the generated type. */
export type QAThinkingStepStatus = 'pending' | 'running' | 'done' | 'failed'

/** @deprecated Use QAResponseRun['terminationReason'] or the generated type. */
export type QATerminationReason =
  | 'completed'
  | 'max_iterations'
  | 'timeout'
  | 'cancelled'
  | 'tool_error'
  | 'model_error'
  | 'policy_denied'

/** @deprecated Use QAAgentToolCall['status'] or the generated type. */
export type QAAgentToolCallStatus = 'running' | 'completed' | 'failed' | 'cancelled'

/** @deprecated Use the generated ReportStatus instead. */
export type ReportStatus =
  | 'draft'
  | 'outline_generating'
  | 'outline_generated'
  | 'content_generating'
  | 'generated'
  | 'exporting'
  | 'exported'
  | 'failed'
  | 'deleted'

